const items = $input.all();
const results = [];

for (const item of items) {
  const payload = item.json;
  const contact = payload.body || payload;

  // Extract email for dedup_key
  const email = (contact.properties?.email?.value || contact.email || '').toLowerCase().trim();

  // Build enrichment object with extended data
  const enrichment = {
    job_title: contact.properties?.jobtitle?.value || contact.jobTitle || contact.job_title || null,
    employee_count: parseInt(contact.properties?.numberofemployees?.value || contact.employeeCount || contact.employee_count || '0') || null,
    deal_size: parseFloat(contact.properties?.hs_deal_amount?.value || contact.dealSize || contact.deal_size || '0') || null,
    website: contact.properties?.website?.value || contact.website || null,
    industry: contact.properties?.industry?.value || contact.industry || null,
    hubspot_vid: contact.vid || contact.id || null,
    lifecycle_stage: contact.properties?.lifecyclestage?.value || null,
    lead_status: contact.properties?.hs_lead_status?.value || null
  };

  // Source metadata from HubSpot
  const sourceMetadata = {
    hubspot_source: contact.properties?.hs_analytics_source?.value || contact.lead_source || null,
    hubspot_source_data_1: contact.properties?.hs_analytics_source_data_1?.value || null,
    hubspot_source_data_2: contact.properties?.hs_analytics_source_data_2?.value || null,
    first_conversion: contact.properties?.first_conversion_event_name?.value || null,
    recent_conversion: contact.properties?.recent_conversion_event_name?.value || null
  };

  results.push({
    json: {
      // For leads table
      email: email,
      dedup_key: email,
      name: `${contact.properties?.firstname?.value || contact.firstName || contact.first_name || ''} ${contact.properties?.lastname?.value || contact.lastName || contact.last_name || ''}`.trim() || null,
      phone: contact.properties?.phone?.value || contact.phone || null,
      company: contact.properties?.company?.value || contact.company || null,
      domain: contact.properties?.website?.value || contact.website || null,
      message: contact.properties?.message?.value || null,
      source: 'hubspot',
      source_campaign: contact.properties?.hs_analytics_source_data_1?.value || null,
      source_metadata: sourceMetadata,
      enrichment: enrichment,
      raw_json: contact,
      is_demo: false,
      received_at: new Date().toISOString(),

      // For scoring (pass through)
      _scoring_data: {
        employee_count: enrichment.employee_count,
        job_title: enrichment.job_title,
        deal_size: enrichment.deal_size,
        lead_source: contact.properties?.hs_analytics_source?.value || contact.lead_source || 'unknown',
        first_conversion: sourceMetadata.first_conversion,
        recent_conversion: sourceMetadata.recent_conversion
      }
    }
  });
}

return results;

