const item = $input.first();
const error = item.json;

// Try to extract lead_id from the execution data
let leadId = null;
try {
  // Check various places where lead_id might be
  if (error.execution?.data?.resultData?.runData) {
    const runData = error.execution.data.resultData.runData;
    // Look in Merge Lead Data or Insert Lead results
    if (runData['Merge Lead Data']?.[0]?.data?.main?.[0]?.[0]?.json?.lead_id) {
      leadId = runData['Merge Lead Data'][0].data.main[0][0].json.lead_id;
    } else if (runData['Insert Lead']?.[0]?.data?.main?.[0]?.[0]?.json?.id) {
      leadId = runData['Insert Lead'][0].data.main[0][0].json.id;
    }
  }
} catch (e) {
  // Could not extract lead_id
}

return [{
  json: {
    lead_id: leadId,
    workflow_name: 'Lead Qualification Pipeline (Adapted)',
    error_message: error.message || 'Unknown error',
    error_node: error.node?.name || 'Unknown',
    error_data: {
      timestamp: error.timestamp,
      workflow_id: error.workflow?.id,
      execution_id: error.execution?.id,
      stack: error.stack
    },
    resolved: false
  }
}];

